import React, { useState } from 'react';
import accessService from '../services/accessService';
import { useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
function RequestAccess(){
  const [form,setForm]=useState({fileId:'', ownerEmail:'', role:'read', message:'', expiry_time:'', geo_lat:null, geo_lon:null, geo_radius_m:100});
  const navigate=useNavigate();
  const submit=async(e)=>{ e.preventDefault(); try{ await accessService.requestAccess(form); alert('Request sent'); navigate('/dashboard'); }catch(e){ alert('Failed'); } };
  const defaultCenter = { lat: 18.5204, lng: 73.8567 };
  const markerIcon = new L.Icon({ iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png', iconSize: [25,41], iconAnchor:[12,41], shadowUrl:'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png', shadowSize:[41,41] });
  function LocationPicker(){
    useMapEvents({ click(e){ setForm({...form, geo_lat:e.latlng.lat, geo_lon:e.latlng.lng}); } });
    return form.geo_lat!=null? <Marker position={{lat:form.geo_lat,lng:form.geo_lon}} icon={markerIcon} />: null;
  }
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 p-8 flex flex-col items-center">
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow-lg p-8">
        <h2 className="text-2xl font-bold mb-4">Request Access</h2>
        <form onSubmit={submit} className="space-y-4">
          <input required placeholder="File ID" value={form.fileId} onChange={e=>setForm({...form,fileId:e.target.value})} className="w-full p-3 border rounded"/>
          <input required placeholder="Owner Email" value={form.ownerEmail} onChange={e=>setForm({...form,ownerEmail:e.target.value})} className="w-full p-3 border rounded"/>
          <select value={form.role} onChange={e=>setForm({...form,role:e.target.value})} className="w-full p-3 border rounded"><option value="read">Read</option><option value="download">Download</option><option value="share">Share</option></select>
          <input type="datetime-local" value={form.expiry_time} onChange={e=>setForm({...form,expiry_time:e.target.value})} className="w-full p-3 border rounded"/>
          <div className="mb-2" style={{ height: '300px', width: '100%' }}>
            <MapContainer center={defaultCenter} zoom={10} style={{ height: '100%', width: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution="&copy; OpenStreetMap contributors" />
              <LocationPicker />
            </MapContainer>
          </div>
          <input type="number" min="10" step="10" placeholder="Radius (meters)" value={form.geo_radius_m} onChange={e=>setForm({...form, geo_radius_m: e.target.value })} className="w-full p-3 border rounded"/>
          <textarea placeholder="Message (optional)" value={form.message} onChange={e=>setForm({...form,message:e.target.value})} className="w-full p-3 border rounded"></textarea>
          <button className="bg-blue-600 text-white px-4 py-2 rounded w-full">Send Request</button>
        </form>
      </div>
    </div>
  );
}
export default RequestAccess;
